-- Generated by scripts/enrich-activity-images.js

-- Generated at 2026-07-23T21:15:22.495Z

-- Organiser images are preferred; listing images are the fallback.

-- Cards without a usable website image render the in-app category illustration.

-- Always serve images securely in the HTTPS mobile app.
update public.activities
set
  image_url = regexp_replace(image_url, '^http://', 'https://', 'i'),
  updated_at = now()
where image_url ~* '^http://';

-- Remove interface assets, tracking pixels, and other non-activity images.
-- The client displays a category illustration whenever image_url is null.
update public.activities
set
  image_url = null,
  image_source_url = null,
  updated_at = now()
where coalesce(image_url, '') ~* '(favicon|icon|logo|wordmark|strapline|sprite|avatar|placeholder|apple-touch|/flags/|site-flag|country-selector|language-selector|facebook[.]com/tr|facebook[.]net/tr|facebook[.](png|jpg|jpeg|webp)|doubleclick|google-analytics|tracking-pixel|/pixel[.]|pixel[.]gif|[.]svg(?:[?#]|$)|google-play|google_play|app-store|app_store|download-button|/small_|150x150|200x200|s200x200|cookie|consent|newsletter|payment|checkout)'
  and (
    coalesce(image_source_url, '') !~* 'happity[.]co[.]uk'
    or coalesce(image_url, '') ~* '(facebook[.]com/tr|facebook[.]net/tr|facebook[.](png|jpg|jpeg|webp)|/small_|150x150|200x200|s200x200)'
  );

-- Applies audited website images and clears legacy Google Places photo values.

with image_updates (
  activity_id,
  google_place_id,
  google_place_uri,
  google_photo_url,
  google_rating,
  google_user_rating_count,
  image_url,
  image_source_url
) as (
  values
    ('2475f7bb-0ddd-4c26-9704-827be0798813'::uuid, 'ChIJ-5-zJPIddkgRSIEKJlIec10'::text, 'https://maps.google.com/?cid=6733759206023397704&g_mp=Cidnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLlNlYXJjaFRleHQQAhgEIAA'::text, null::text, 4.5::numeric, 108::integer, 'https://happity-production.s3.amazonaws.com/uploads/company/logo/10558/event_Treasure_Me_Kids_London_logo.jpeg?v=1775354189'::text, 'https://www.happity.co.uk/schedules/treasure-me-kids-london-london-walthamstow-toy-library-baby-massage-course-by-treasure-me-kids-london'::text)
)
update public.activities as activities
set
  google_place_id = coalesce(image_updates.google_place_id, activities.google_place_id),
  google_place_uri = coalesce(image_updates.google_place_uri, activities.google_place_uri),
  google_photo_url = null,
  google_rating = coalesce(image_updates.google_rating, activities.google_rating),
  google_user_rating_count = coalesce(image_updates.google_user_rating_count, activities.google_user_rating_count),
  image_url = image_updates.image_url,
  image_source_url = image_updates.image_source_url,
  updated_at = now()
from image_updates
where activities.activity_id = image_updates.activity_id;

